Assess-eligibility-with-common.body:
fn(state => {
  const { mother_age, household_income } = state.data;

  // Define eligibility criteria
  const MIN_MOTHER_AGE = 18;
  const MAX_HOUSEHOLD_INCOME = 50000;

  const isEligible =
    mother_age >= MIN_MOTHER_AGE &&
    household_income <= MAX_HOUSEHOLD_INCOME;

  return {
    ...state,
    data: {
      ...state.data,
      eligibility: isEligible,
    },
  };
});
